import { Injectable, Logger } from '@nestjs/common';
import { GitHub } from 'arctic';

import {
	GITHUB_CALLBACK_URL,
	GITHUB_CLIENT_ID,
	GITHUB_CLIENT_SECRET,
} from '@constants/env-variables.constant';
import { EnvConfigService } from '@modules/env-config/env-config.service';
import { IOAuthProfile } from '@modules/auth/types/auth.interface';

@Injectable()
export class GithubStrategy {
	private readonly github: GitHub;
	private readonly logger = new Logger(GithubStrategy.name);

	constructor(private readonly configService: EnvConfigService) {
		const clientId = this.configService.get<string>({ key: GITHUB_CLIENT_ID });
		const clientSecret = this.configService.get<string>({ key: GITHUB_CLIENT_SECRET });
		const callbackUrl = this.configService.get<string>({ key: GITHUB_CALLBACK_URL });

		this.github = new GitHub(clientId, clientSecret, callbackUrl);
	}

	createAuthorizationURL({
		state,
	}: {
		state: string;
		codeVerifier: string;
	}): URL {
		return this.github.createAuthorizationURL(state, ['user:email']);
	}

	async validateAuthorizationCode({
		code,
	}: {
		code: string;
		codeVerifier: string;
	}): Promise<{ accessToken: string }> {
		const tokens = await this.github.validateAuthorizationCode(code);
		return { accessToken: tokens.accessToken() };
	}

	async getUserProfile({
		accessToken,
	}: {
		accessToken: string;
	}): Promise<IOAuthProfile> {
		try {
			const response = await fetch('https://api.github.com/user', {
				headers: {
					Authorization: `Bearer ${accessToken}`,
					Accept: 'application/json',
				},
			});

			if (!response.ok) {
				throw new Error(`GitHub API returned ${response.status}`);
			}

			const data = (await response.json()) as {
				id: number;
				email: string | null;
				name: string | null;
				avatar_url: string | null;
				login: string;
			};

			let email = data.email;

			if (!email) {
				const emailsResponse = await fetch('https://api.github.com/user/emails', {
					headers: {
						Authorization: `Bearer ${accessToken}`,
						Accept: 'application/json',
					},
				});

				if (!emailsResponse.ok) {
					throw new Error(`GitHub emails API returned ${emailsResponse.status}`);
				}

				const emails = (await emailsResponse.json()) as Array<{
					email: string;
					primary: boolean;
					verified: boolean;
				}>;

				const primaryEmail = emails.find((e) => e.primary && e.verified);
				email = primaryEmail?.email ?? null;
			}

			return {
				provider: 'github',
				provider_id: String(data.id),
				email: email ?? '',
				name: data.name,
				avatar_url: data.avatar_url,
			};
		} catch (error) {
			this.logger.error('Failed to fetch GitHub user profile', error);
			throw error;
		}
	}
}

import { Injectable, Logger } from '@nestjs/common';
import { Google } from 'arctic';

import {
	GOOGLE_CALLBACK_URL,
	GOOGLE_CLIENT_ID,
	GOOGLE_CLIENT_SECRET,
} from '@constants/env-variables.constant';
import { EnvConfigService } from '@modules/env-config/env-config.service';
import { IOAuthProfile } from '@modules/auth/types/auth.interface';

@Injectable()
export class GoogleStrategy {
	private readonly google: Google;
	private readonly logger = new Logger(GoogleStrategy.name);

	constructor(private readonly configService: EnvConfigService) {
		const clientId = this.configService.get<string>({ key: GOOGLE_CLIENT_ID });
		const clientSecret = this.configService.get<string>({ key: GOOGLE_CLIENT_SECRET });
		const callbackUrl = this.configService.get<string>({ key: GOOGLE_CALLBACK_URL });

		this.google = new Google(clientId, clientSecret, callbackUrl);
	}

	createAuthorizationURL({
		state,
		codeVerifier,
	}: {
		state: string;
		codeVerifier: string;
	}): URL {
		return this.google.createAuthorizationURL(state, codeVerifier, [
			'openid',
			'email',
			'profile',
		]);
	}

	async validateAuthorizationCode({
		code,
		codeVerifier,
	}: {
		code: string;
		codeVerifier: string;
	}): Promise<{ accessToken: string }> {
		const tokens = await this.google.validateAuthorizationCode(code, codeVerifier);
		return { accessToken: tokens.accessToken() };
	}

	async getUserProfile({
		accessToken,
	}: {
		accessToken: string;
	}): Promise<IOAuthProfile> {
		try {
			const response = await fetch(
				'https://openidconnect.googleapis.com/v1/userinfo',
				{
					headers: {
						Authorization: `Bearer ${accessToken}`,
						Accept: 'application/json',
					},
				},
			);

			if (!response.ok) {
				throw new Error(`Google API returned ${response.status}`);
			}

			const data = (await response.json()) as {
				sub: string;
				email: string;
				name: string | null;
				picture: string | null;
			};

			return {
				provider: 'google',
				provider_id: data.sub,
				email: data.email,
				name: data.name,
				avatar_url: data.picture,
			};
		} catch (error) {
			this.logger.error('Failed to fetch Google user profile', error);
			throw error;
		}
	}
}

import { Logger } from '@nestjs/common';
import { Test, TestingModule } from '@nestjs/testing';

import { EnvConfigService } from '@modules/env-config/env-config.service';
