};

describe('GithubStrategy', () => {
	let strategy: GithubStrategy;
	let fetchSpy: jest.SpyInstance;

	beforeEach(async () => {
		jest.clearAllMocks();

		const module: TestingModule = await Test.createTestingModule({
			providers: [
				GithubStrategy,
				{ provide: EnvConfigService, useValue: mockEnvConfigService },
			],
		}).compile();

		strategy = module.get<GithubStrategy>(GithubStrategy);

		jest.spyOn(Logger.prototype, 'log').mockImplementation(jest.fn());
		jest.spyOn(Logger.prototype, 'error').mockImplementation(jest.fn());
	});

	afterEach(() => {
		jest.clearAllMocks();
	});

	it('should be defined', () => {
		expect(strategy).toBeDefined();
	});

	describe('createAuthorizationURL', () => {
		it('should return a URL', () => {
			const result = strategy.createAuthorizationURL({
				state: 'test-state',
				codeVerifier: 'test-verifier',
			});

			expect(result).toBeInstanceOf(URL);
			expect(result.toString()).toContain('github.com');
		});
	});

	describe('validateAuthorizationCode', () => {
		it('should return accessToken', async () => {
			const mockTokens = {
				accessToken: jest.fn().mockReturnValue('mock-access-token'),
			};

			fetchSpy = jest.spyOn(global, 'fetch').mockResolvedValueOnce({
				ok: true,
				json: jest.fn().mockResolvedValue({
					access_token: 'mock-access-token',
					token_type: 'bearer',
				}),
			} as unknown as Response);

			const result = await strategy.validateAuthorizationCode({
				code: 'test-code',
				codeVerifier: 'test-verifier',
			});

			expect(result).toHaveProperty('accessToken');
			expect(typeof result.accessToken).toBe('string');
			void mockTokens;
		});
	});

	describe('getUserProfile', () => {
		it('should return profile with public email', async () => {
			fetchSpy = jest.spyOn(global, 'fetch').mockResolvedValueOnce({
				ok: true,
				json: jest.fn().mockResolvedValue({
					id: 12345,
					email: 'user@example.com',
					name: 'Test User',
					avatar_url: 'https://avatars.githubusercontent.com/u/12345',
					login: 'testuser',
				}),
			} as unknown as Response);

			const result = await strategy.getUserProfile({
				accessToken: 'mock-access-token',
			});

			expect(result).toEqual({
				provider: 'github',
				provider_id: '12345',
				email: 'user@example.com',
				name: 'Test User',
				avatar_url: 'https://avatars.githubusercontent.com/u/12345',
			});
			expect(fetchSpy).toHaveBeenCalledTimes(1);
		});

		it('should fall back to /user/emails when no public email', async () => {
			fetchSpy = jest
				.spyOn(global, 'fetch')
				.mockResolvedValueOnce({
					ok: true,
					json: jest.fn().mockResolvedValue({
						id: 12345,
						email: null,
						name: 'Test User',
						avatar_url: 'https://avatars.githubusercontent.com/u/12345',
						login: 'testuser',
					}),
				} as unknown as Response)
				.mockResolvedValueOnce({
					ok: true,
					json: jest.fn().mockResolvedValue([
						{ email: 'noreply@users.noreply.github.com', primary: false, verified: true },
						{ email: 'user@example.com', primary: true, verified: true },
					]),
				} as unknown as Response);

			const result = await strategy.getUserProfile({
				accessToken: 'mock-access-token',
			});

			expect(result.email).toBe('user@example.com');
			expect(fetchSpy).toHaveBeenCalledTimes(2);
		});

		it('should throw on non-OK response', async () => {
			fetchSpy = jest.spyOn(global, 'fetch').mockResolvedValueOnce({
				ok: false,
				status: 401,
			} as unknown as Response);

			await expect(
				strategy.getUserProfile({ accessToken: 'bad-token' }),
			).rejects.toThrow('GitHub API returned 401');
		});
	});
});

